import{c as e,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Agent Harness for Large Language Model Agents: A Survey","description":"","frontmatter":{"url":"https://www.preprints.org/manuscript/202604.0428/v1","title":"Agent Harness for Large Language Model Agents: A Survey","date":"2026-04-07T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-07-agent-harness-survey.md","filePath":"research/ai-articles/scored/2026-04-07-agent-harness-survey.md","lastUpdated":1779796674000}'),l={name:"research/ai-articles/scored/2026-04-07-agent-harness-survey.md"};function o(s,t,i,d,h,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="agent-harness-for-large-language-model-agents-a-survey" tabindex="-1">Agent Harness for Large Language Model Agents: A Survey <a class="header-anchor" href="#agent-harness-for-large-language-model-agents-a-survey" aria-label="Permalink to &quot;Agent Harness for Large Language Model Agents: A Survey&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://www.preprints.org/manuscript/202604.0428/v1" target="_blank" rel="noreferrer">https://www.preprints.org/manuscript/202604.0428/v1</a><br><strong>作者</strong>：Qianyu Meng 等 9 位<br><strong>發表日期</strong>：2026-04-07<br><strong>評分日期</strong>：2026-05-05</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><p>Agent 執行基礎設施——而非底層模型能力——決定了部署 LLM 系統的可靠性。</p><blockquote><p>「harness 層級的改變單獨就能在編碼 benchmark 上產生高達 10× 的效益提升，而無需修改模型。」</p></blockquote><p>從 OpenAI、Stripe 和 METR 的從業者報告中得到佐證：基礎設施投資帶來的效能改善<strong>可媲美或超越</strong>模型升級。</p><h3 id="正式定義框架-h-e-t-c-s-l-v" tabindex="-1">正式定義框架：H=(E,T,C,S,L,V) <a class="header-anchor" href="#正式定義框架-h-e-t-c-s-l-v" aria-label="Permalink to &quot;正式定義框架：H=(E,T,C,S,L,V)&quot;">​</a></h3><h4 id="e-—-execution-loop-執行循環" tabindex="-1">E — Execution Loop（執行循環） <a class="header-anchor" href="#e-—-execution-loop-執行循環" aria-label="Permalink to &quot;E — Execution Loop（執行循環）&quot;">​</a></h4><p>核心控制流，主導模型與工具的互動：</p><ul><li>Plan-act-observe 循環</li><li>Verifier-operator-feedback 模式</li><li>Agent-computer interface 流程</li><li>多 Agent 協調</li></ul><h4 id="t-—-tool-integration-工具整合" tabindex="-1">T — Tool Integration（工具整合） <a class="header-anchor" href="#t-—-tool-integration-工具整合" aria-label="Permalink to &quot;T — Tool Integration（工具整合）&quot;">​</a></h4><p>模型如何存取和使用外部能力：</p><ul><li>API/工具呼叫語義</li><li>錯誤處理和重試邏輯</li><li>工具抽象和組合</li></ul><h4 id="c-—-context-management-context-管理" tabindex="-1">C — Context Management（Context 管理） <a class="header-anchor" href="#c-—-context-management-context-管理" aria-label="Permalink to &quot;C — Context Management（Context 管理）&quot;">​</a></h4><p>資訊如何在模型間流動：</p><ul><li>輸入提示詞構建</li><li>歷史壓縮和 windowing</li><li>Token 預算分配</li></ul><h4 id="s-—-state-persistence-狀態持久化" tabindex="-1">S — State Persistence（狀態持久化） <a class="header-anchor" href="#s-—-state-persistence-狀態持久化" aria-label="Permalink to &quot;S — State Persistence（狀態持久化）&quot;">​</a></h4><p>系統狀態如何跨互動持久化：</p><ul><li>長期記憶機制</li><li>基於文件的狀態儲存</li><li>Session 管理</li></ul><h4 id="l-—-lifecycle-governance-生命週期治理" tabindex="-1">L — Lifecycle Governance（生命週期治理） <a class="header-anchor" href="#l-—-lifecycle-governance-生命週期治理" aria-label="Permalink to &quot;L — Lifecycle Governance（生命週期治理）&quot;">​</a></h4><p>系統如何管理資源和執行政策：</p><ul><li>預算追蹤（token、成本、時間）</li><li>核准流程和上升機制</li><li>檢查點和恢復</li></ul><h4 id="v-—-evaluation-interfaces-評估介面" tabindex="-1">V — Evaluation Interfaces（評估介面） <a class="header-anchor" href="#v-—-evaluation-interfaces-評估介面" aria-label="Permalink to &quot;V — Evaluation Interfaces（評估介面）&quot;">​</a></h4><p>系統效能如何被測量和優化：</p><ul><li>結果評分</li><li>Trace 分析</li><li>改進反饋循環</li></ul><h3 id="歷史脈絡" tabindex="-1">歷史脈絡 <a class="header-anchor" href="#歷史脈絡" aria-label="Permalink to &quot;歷史脈絡&quot;">​</a></h3><p>三條獨立的脈絡匯聚到共同模式：</p><ol><li><strong>軟體測試 harness</strong>：控制執行環境 + stimulus-response 觀察</li><li><strong>強化學習環境</strong>（OpenAI Gym）：明確的狀態、動作、獎勵協議</li><li><strong>早期 LLM 框架</strong>（LangChain、AutoGPT）：逐漸形式化的執行模式</li></ol><h3 id="_22-個系統的實證分類" tabindex="-1">22 個系統的實證分類 <a class="header-anchor" href="#_22-個系統的實證分類" aria-label="Permalink to &quot;22 個系統的實證分類&quot;">​</a></h3><h4 id="執行循環模式" tabindex="-1">執行循環模式 <a class="header-anchor" href="#執行循環模式" aria-label="Permalink to &quot;執行循環模式&quot;">​</a></h4><ul><li>單 Agent 循環（基本 ReAct）</li><li>規劃者-驗證者結構（分層規劃）</li><li>Agent-computer interface 循環</li><li>多 Agent 協調（平行/循序 Agent 團隊）</li></ul><h4 id="工具整合方式" tabindex="-1">工具整合方式 <a class="header-anchor" href="#工具整合方式" aria-label="Permalink to &quot;工具整合方式&quot;">​</a></h4><ul><li>直接函式呼叫</li><li>API 工具抽象（OpenAI Functions、Claude Tools）</li><li>可執行程式碼生成和沙箱化</li><li>Web 自動化和 UI 互動</li></ul><h4 id="狀態管理策略" tabindex="-1">狀態管理策略 <a class="header-anchor" href="#狀態管理策略" aria-label="Permalink to &quot;狀態管理策略&quot;">​</a></h4><ul><li>暫態（對話歷史）</li><li>文件狀態（持久文件、日誌）</li><li>資料庫狀態（結構化記憶）</li><li>混合方法（多層狀態）</li></ul><h3 id="九大跨領域技術挑戰" tabindex="-1">九大跨領域技術挑戰 <a class="header-anchor" href="#九大跨領域技術挑戰" aria-label="Permalink to &quot;九大跨領域技術挑戰&quot;">​</a></h3><table tabindex="0"><thead><tr><th>挑戰</th><th>說明</th></tr></thead><tbody><tr><td><strong>沙箱和安全</strong></td><td>隔離執行以防止資源耗盡、資料洩漏、意外系統修改</td></tr><tr><td><strong>評估和評分</strong></td><td>無確定性答案時的成功標準；exact-match + behavioral + LLM-jury 組合</td></tr><tr><td><strong>協議標準化</strong></td><td>缺乏通用 agent-harness 通訊協議；MCP vs. A2A 競爭</td></tr><tr><td><strong>計算經濟學</strong></td><td>在任務複雜度和推理深度增加時管理 token 消耗</td></tr><tr><td><strong>長 Context 管理</strong></td><td>處理延伸互動歷史和診斷 trace</td></tr><tr><td><strong>工具組合和依賴</strong></td><td>協調複雜多工具工作流，並明確追蹤依賴</td></tr><tr><td><strong>可重現性和追蹤</strong></td><td>捕捉完整執行 trace 用於除錯和系統比較</td></tr><tr><td><strong>失敗恢復和上升</strong></td><td>當 agent 達到邊界（信心極限、資源限制）時的健壯恢復</td></tr><tr><td><strong>遷移和泛化</strong></td><td>讓發現的 harness 模式跨不同模型、領域和任務族群遷移</td></tr></tbody></table><h3 id="實證證據" tabindex="-1">實證證據 <a class="header-anchor" href="#實證證據" aria-label="Permalink to &quot;實證證據&quot;">​</a></h3><ul><li><strong>HAL</strong>：同樣模型在不同 harness 設計上產生 2-4× 效能差異</li><li><strong>SWE-bench 分析</strong>：harness 基礎設施佔效能差異的 &gt;40%</li><li><strong>AgencyBench</strong>：多 Agent 協調模式（規劃者-驗證者、ensemble 投票）比單 Agent 基準一致高出 15-30%，即使使用相同基礎模型</li></ul><h3 id="對-workspace-的啟示" tabindex="-1">對 Workspace 的啟示 <a class="header-anchor" href="#對-workspace-的啟示" aria-label="Permalink to &quot;對 Workspace 的啟示&quot;">​</a></h3><ol><li><strong>H=(E,T,C,S,L,V) 框架作為 harness 審計工具</strong>：可用於系統性稽核 cc-workspace 的六個維度</li><li><strong>九大挑戰的對應機制</strong>：cc-workspace 已有相應設計（L→生命週期 hooks、C→compact 觸發、V→/deep-review）</li><li><strong>2-4× 效能差異</strong>：harness 改善 ≥ 模型升級的直接理論支撐</li><li><strong>標準化評估</strong>：harness-eval skill 的設計應覆蓋 V（評估介面）維度</li></ol><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>7/10</td><td>H=(E,T,C,S,L,V) 框架可作為 harness-eval 的結構骨架；九大挑戰提供系統性審計清單</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>正式化六分量框架和 22 個系統分析是學術貢獻；但觀念本身並非全新</td></tr><tr><td>C. 證據品質</td><td>8/10</td><td>HAL、SWE-bench、AgencyBench 三個實驗支撐，量化數據（10×、&gt;40%、15-30%）具體</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>22 個系統的詳細分類、歷史脈絡分析、九大挑戰的系統性描述</td></tr><tr><td>E. 泛化性</td><td>9/10</td><td>正式框架設計為跨系統、跨模型、跨任務通用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.65/10</strong></td><td>7×0.3 + 7×0.2 + 8×0.2 + 8×0.15 + 9×0.15 = 2.1+1.4+1.6+1.2+1.35</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code>（H=(E,T,C,S,L,V) 框架作為設計稽核工具）<br><strong>整合狀態</strong>：待實作</p><p><strong>TODO</strong>：</p><ul><li>在 harness-design.md 加入 H=(E,T,C,S,L,V) 六維框架作為稽核 checklist</li><li>harness-eval skill 的 scorecard 可參考本 survey 的九大挑戰設計評估維度</li></ul>',49)])])}const p=e(l,[["render",o]]);export{u as __pageData,p as default};
